  ('elementary-64311456-moex-00555', 'elementary-64311456', 'elementary-64311456-moex-112-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '全面性社區發展的行動中，蘊含一些可能的現象，下列敘述何者錯誤？', '["地方性：服務是以鄰里而非中央的辦公室為場所", "外展：期待社區居民能走出家外，到活動中心與他人互動", "與民有約：第一線員工能夠與民眾直接接觸", "權力下放：讓社區人士參與地方服務的管理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "13927e4759e3", "answer_pdf_sha1": "9f92f5035bc4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00556', 'elementary-64311456', 'elementary-64311456-moex-112-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '社區需求分析可運用多種資料蒐集的方法，下列何者最符合「參與觀察法」的實施方式？', '["透過社區居民會議討論的形式，蒐集社區的意見", "透過電話的方式，以結構性的訪談問項為基礎，蒐集社區居民對特定議題的回應", "向社區的公務機構申請相關的輔導記錄與統計資料，據以瞭解社區的問題", "實際參加社區的活動，在過程中瞭解居民的偏好和需求"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "13927e4759e3", "answer_pdf_sha1": "9f92f5035bc4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00557', 'elementary-64311456', 'elementary-64311456-moex-112-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '社區工作的實施程序大致可包含以下幾個步驟：①確認社區議題  ②進入與認識社區  ③發展社區工作', '["將社區工作行動轉移給社區居民  ⑤執行社區計畫。請依據實施的順序，排列出正確的步驟", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "13927e4759e3", "answer_pdf_sha1": "9f92f5035bc4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00558', 'elementary-64311456', 'elementary-64311456-moex-112-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '個案工作結案階段的重點，不包括下列何者？', '["加強服務對象在處遇過程中所獲得之成果", "解決服務中所產生的（反）情感轉移等議題", "催化服務對象分享家庭背景、互動關係的程度", "了解及強化服務對象在會談室之外類化所學的程度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "13927e4759e3", "answer_pdf_sha1": "9f92f5035bc4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00559', 'elementary-64311456', 'elementary-64311456-moex-112-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '依據會談訪視的步驟，下列各項工作排列順序，何者正確？①撰寫訪視記錄、擬訂工作計畫  ②約訪、', '["與案主建立關係、清楚說明社會工作者的來意", "針對案主需求進行評估、具體瞭解案主 所遭遇的議題", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "13927e4759e3", "answer_pdf_sha1": "9f92f5035bc4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00560', 'elementary-64311456', 'elementary-64311456-moex-112-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '社會工作者充分提供案主所需的訊息，並且尊重案主自我的責任與決定。這是屬於下列何種專業關係原 則？', '["非批判的態度", "個別化", "有目的的表達情感", "案主自我抉擇"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "13927e4759e3", "answer_pdf_sha1": "9f92f5035bc4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00561', 'elementary-64311456', 'elementary-64311456-moex-112-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '團體內各個體間的差異逐漸拉大，進而擁有各自的功能，這是下列何種過程？', '["分化", "平衡", "制衡", "穩定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "13927e4759e3", "answer_pdf_sha1": "9f92f5035bc4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00562', 'elementary-64311456', 'elementary-64311456-moex-112-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '關於個案工作專業關係的敘述，下列何者錯誤？', '["社會工作者與服務對象的專業關係是個案工作的重要基礎，若沒有建立信任的關係，服務計畫很難執行", "專業關係是一種互惠的關係", "社會工作者以非批判的態度與服務對象工作是專業關係中的重要原則", "專業關係是有明確目的的互動，是為了有目的、有方向的個案工作而建立的關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "13927e4759e3", "answer_pdf_sha1": "9f92f5035bc4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00563', 'elementary-64311456', 'elementary-64311456-moex-112-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '關於團體工作模式中的交互模式，下列敘述何者正確？', '["僅適用於社會層面的改變", "關心社區的發展與問題且在睦鄰中心實施", "社會工作者催化團體成員互動來達到個人改變", "不預先設定處遇的目標"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "13927e4759e3", "answer_pdf_sha1": "9f92f5035bc4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00564', 'elementary-64311456', 'elementary-64311456-moex-112-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', '關於團體第一次聚會可能會出現的現象與動力，下列敘述何者錯誤？', '["團體會出現趨避的衝突，想要參與又害怕參加", "團體成員會猜測團體工作者的意圖，出現試探的行為", "因期待團體的開始，通常會自發而流暢地自我揭露，對團體充滿信任", "為了增加安全感，會尋找共同性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "13927e4759e3", "answer_pdf_sha1": "9f92f5035bc4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL)
